import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';

interface User {
  id: string;
  email: string;
  name: string;
  role?: string;
  company_id?: string;
}

interface AuthContextType {
  user: User | null;
  token: string | null;
  isLoading: boolean;
  signOut: () => Promise<void>;
  signInDemo: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const checkAuth = async () => {
      // Check for dev token first
      const devToken = localStorage.getItem('DEV_TOKEN');
      if (devToken) {
        setToken(devToken);
        setUser({
          id: 'dev-user-id',
          email: 'demo@bmbuild.com',
          name: 'Usuario Demo',
          role: 'admin',
          company_id: '77777777-7777-7777-7777-777777777777'
        });
        setIsLoading(false);
        return;
      }

      // Get initial session
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
        setToken(session.access_token);
        setUser({
          id: session.user.id,
          email: session.user.email || '',
          name: session.user.user_metadata.name || session.user.email?.split('@')[0] || 'Usuario',
          role: session.user.user_metadata.role || 'manager',
          company_id: session.user.user_metadata.company_id
        });
      }
      setIsLoading(false);
    };

    checkAuth();

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      // If we are in dev mode, don't let supabase override unless it's a real logout
      if (localStorage.getItem('DEV_TOKEN') && !session) {
        return;
      }

      if (session) {
        setToken(session.access_token);
        setUser({
          id: session.user.id,
          email: session.user.email || '',
          name: session.user.user_metadata.name || session.user.email?.split('@')[0] || 'Usuario',
          role: session.user.user_metadata.role || 'manager',
          company_id: session.user.user_metadata.company_id
        });
      } else {
        setToken(null);
        setUser(null);
      }
      setIsLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const signOut = async () => {
    localStorage.removeItem('DEV_TOKEN');
    localStorage.removeItem('sb-user-id');
    await supabase.auth.signOut();
    setToken(null);
    setUser(null);
  };

  const signInDemo = () => {
    localStorage.setItem('DEV_TOKEN', 'dev-token');
    setToken('dev-token');
    setUser({
      id: 'dev-user-id',
      email: 'demo@bmbuild.com',
      name: 'Usuario Demo',
      role: 'admin',
      company_id: '77777777-7777-7777-7777-777777777777'
    });
  };

  return (
    <AuthContext.Provider value={{ user, token, signOut, signInDemo, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import React, { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem('theme');
    if (saved === 'light' || saved === 'dark') return saved;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove('light', 'dark');
    root.classList.add(theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => (prev === 'light' ? 'dark' : 'light'));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

import { useState } from 'react';
import type { ReactNode, FormEvent } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import api from '../../lib/api';
import {
  Plus, Search, X, Copy, Trash2, Pencil, Calculator,
  Package, HardHat, Wrench, Check, ChevronDown, ChevronRight,
  TrendingUp, Layers, DollarSign
} from 'lucide-react';
import { PageHeader } from '../../components/common/PageHeader';

// ÔöÇÔöÇÔöÇ Types ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
type ResourceType = 'material' | 'labor' | 'equipment';
// ApuUnit type is deprecated in favor of standardized units

interface Resource {
  id: string;
  name: string;
  type: ResourceType;
  unit_id: string;
  unit?: { symbol: string; name: string };
  base_price: number;
}

interface Unit {
  id: string;
  name: string;
  symbol: string;
}

interface ApuResourceEntry {
  id?: string;
  resource_id: string;
  resource_type: ResourceType;
  coefficient: number;
  resource?: Resource;
}

interface ApuTemplate {
  id: string;
  name: string;
  unit_id: string;
  unit?: Unit;
  description?: string;
  unit_cost: number;
  apu_resources: ApuResourceEntry[];
}

// ÔöÇÔöÇÔöÇ Utilities ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function formatCLP(v: number) {
  return new Intl.NumberFormat('es-CL', { style: 'currency', currency: 'CLP', maximumFractionDigits: 0 }).format(v);
}

// APU_UNITS is now fetched from API

const RES_TYPE_ICONS: Record<ResourceType, ReactNode> = {
  material: <Package size={12} />,
  labor: <HardHat size={12} />,
  equipment: <Wrench size={12} />,
};

const RES_TYPE_COLORS: Record<ResourceType, string> = {
  material: 'text-blue-400 bg-blue-500/10',
  labor: 'text-violet-400 bg-violet-500/10',
  equipment: 'text-amber-400 bg-amber-500/10',
};

// ÔöÇÔöÇÔöÇ APU Editor Modal ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
interface ApuEditorProps {
  initial?: Partial<ApuTemplate>;
  resources: Resource[];
  onSave: (data: any) => void;
  onCancel: () => void;
  isLoading?: boolean;
  units: Unit[];
}

function ApuEditor({ initial, resources, onSave, onCancel, isLoading, units }: ApuEditorProps) {
  const [name, setName] = useState(initial?.name ?? '');
  const [unitId, setUnitId] = useState(initial?.unit_id ?? '');
  const [description, setDescription] = useState(initial?.description ?? '');
  const [entries, setEntries] = useState<ApuResourceEntry[]>(
    initial?.apu_resources?.map((r) => ({
      resource_id: r.resource_id,
      resource_type: r.resource_type,
      coefficient: Number(r.coefficient),
      resource: r.resource,
    })) ?? []
  );
  const [resourceSearch, setResourceSearch] = useState('');

  const filteredResources = resources.filter((r) =>
    r.name.toLowerCase().includes(resourceSearch.toLowerCase())
  );

  const addEntry = (resource: Resource) => {
    if (entries.some((e) => e.resource_id === resource.id)) return;
    setEntries([...entries, {
      resource_id: resource.id,
      resource_type: resource.type,
      coefficient: 1,
      resource,
    }]);
    setResourceSearch('');
  };

  const removeEntry = (resourceId: string) =>
    setEntries(entries.filter((e) => e.resource_id !== resourceId));

  const updateCoeff = (resourceId: string, coeff: number) =>
    setEntries(entries.map((e) => e.resource_id === resourceId ? { ...e, coefficient: coeff } : e));

  const unitCost = entries.reduce((sum, e) => {
    const price = Number(e.resource?.base_price ?? 0);
    return sum + price * e.coefficient;
  }, 0);

  const handleSubmit = (ev: FormEvent) => {
    ev.preventDefault();
    onSave({
      name,
      unit_id: unitId,
      description,
      apu_resources: entries.map((e) => ({
        resource_id: e.resource_id,
        resource_type: e.resource_type,
        coefficient: e.coefficient,
      })),
    });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={onCancel} />
      <form
        onSubmit={handleSubmit}
        className="relative bg-gray-950 border border-white/10 rounded-3xl w-full max-w-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] z-10 overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-200"
      >
        {/* Header */}
        <div className="px-8 pt-8 pb-6 border-b border-white/5 relative bg-gray-900/20">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-blue-600/20 border border-blue-500/30 rounded-xl flex items-center justify-center">
                <Calculator size={20} className="text-blue-400" />
              </div>
              <div>
                <h3 className="text-white font-bold text-xl">{initial?.id ? 'Editar Partida APU' : 'Crear Nueva Partida'}</h3>
                <p className="text-gray-500 text-xs">Configure los recursos y rendimientos para su an├ílisis</p>
              </div>
            </div>
            <button
              type="button"
              onClick={onCancel}
              className="w-10 h-10 flex items-center justify-center rounded-xl bg-gray-900 border border-white/5 text-gray-500 hover:text-white transition-colors"
            >
              <X size={18} />
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-wider ml-1">Nombre de la partida</label>
              <input
                value={name}
                onChange={(e) => setName(e.target.value)}
                required
                placeholder="Ej: Radier hormig├│n G25 e=10cm"
                className="w-full bg-gray-900/50 border border-white/10 rounded-xl px-4 py-3 text-white text-sm outline-none focus:border-blue-500/50 focus:ring-4 focus:ring-blue-500/5 transition-all"
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[11px] font-bold text-gray-400 uppercase tracking-wider ml-1">Unidad base</label>
              <select
                value={unitId}
                onChange={(e) => setUnitId(e.target.value)}
                required
                className="w-full bg-gray-900/50 border border-white/10 rounded-xl px-4 py-3 text-white text-sm outline-none focus:border-blue-500/50 focus:ring-4 focus:ring-blue-500/5 transition-all appearance-none cursor-pointer"
              >
                <option value="" disabled>Seleccionar unidad...</option>
                {units.map((u) => <option key={u.id} value={u.id}>{u.symbol} - {u.name}</option>)}
              </select>
            </div>
          </div>

          <div className="mt-4 space-y-1.5">
            <label className="text-[11px] font-bold text-gray-400 uppercase tracking-wider ml-1">Descripci├│n</label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Descripci├│n opcional de la partida..."
              className="w-full bg-gray-900/50 border border-white/10 rounded-xl px-4 py-2 text-white text-sm outline-none focus:border-blue-500/50 focus:ring-4 focus:ring-blue-500/5 transition-all resize-none h-20"
            />
          </div>
        </div>

        {/* Resources Section */}
        <div className="px-8 py-6 flex-1 overflow-y-auto">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h4 className="text-sm font-bold text-white uppercase tracking-wider flex items-center gap-2">
                <Layers size={16} className="text-blue-400" />
                Matriz de Recursos
              </h4>
              <p className="text-gray-500 text-[10px] mt-0.5">Defina materiales, mano de obra y equipos necesarios</p>
            </div>
            <div className="bg-emerald-500/10 border border-emerald-500/20 px-4 py-2 rounded-2xl">
              <span className="text-[10px] text-emerald-400/80 uppercase font-bold tracking-wider">Costo Unit. Estimado</span>
              <div className="text-emerald-400 font-black text-lg tabular-nums">
                {formatCLP(unitCost)}<span className="text-xs opacity-60 ml-1">/ {units.find(u => u.id === unitId)?.symbol || '?'}</span>
              </div>
            </div>
          </div>

          {/* New Resource Search */}
          <div className="relative mb-6">
            <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" />
            <input
              value={resourceSearch}
              onChange={(e) => setResourceSearch(e.target.value)}
              placeholder="Escriba para buscar y agregar recursos..."
              className="w-full bg-gray-950 border border-white/5 rounded-2xl pl-12 pr-4 py-3.5 text-white text-sm outline-none focus:border-blue-500/30 transition-all placeholder:text-gray-600"
            />
            {resourceSearch && (
              <div className="absolute top-full left-0 right-0 mt-2 bg-gray-900 border border-white/10 rounded-2xl overflow-hidden z-20 shadow-2xl overflow-y-auto max-h-[250px] animate-in fade-in slide-in-from-top-2 duration-200">
                {filteredResources.slice(0, 15).map((r) => (
                  <button
                    key={r.id}
                    type="button"
                    onClick={() => addEntry(r)}
                    disabled={entries.some((e) => e.resource_id === r.id)}
                    className="w-full flex items-center gap-4 px-4 py-3 hover:bg-white/5 transition-colors text-left disabled:opacity-40 group"
                  >
                    <div className={`w-8 h-8 flex items-center justify-center rounded-lg ${RES_TYPE_COLORS[r.type]} group-hover:scale-110 transition-transform`}>
                      {RES_TYPE_ICONS[r.type]}
                    </div>
                    <div className="flex-1">
                      <p className="text-white text-sm font-medium">{r.name}</p>
                      <p className="text-gray-500 text-[10px] tracking-wide uppercase">{r.type} ┬À {r.unit?.symbol || '-'}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-white text-sm font-bold tabular-nums">{formatCLP(Number(r.base_price))}</p>
                      <p className="text-gray-500 text-[10px]">Precio base</p>
                    </div>
                  </button>
                ))}
                {filteredResources.length === 0 && (
                  <div className="p-8 text-center">
                    <Package size={32} className="text-gray-700 mx-auto mb-2" />
                    <p className="text-gray-500 text-xs">No se encontraron recursos</p>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Resources List */}
          <div className="space-y-4">
            {entries.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-12 bg-gray-900/20 border border-dashed border-white/5 rounded-3xl">
                <div className="w-12 h-12 bg-gray-800 rounded-full flex items-center justify-center mb-3">
                  <Package size={20} className="text-gray-600" />
                </div>
                <p className="text-gray-500 text-sm">Agregue recursos para calcular el costo</p>
              </div>
            ) : (
              <div className="space-y-2">
                {/* Custom Table Component */}
                {entries.map((entry) => (
                  <div
                    key={entry.resource_id}
                    className="flex items-center gap-4 bg-gray-900/40 hover:bg-gray-900/60 border border-white/5 rounded-2xl p-4 transition-all group"
                  >
                    <div className={`w-10 h-10 flex items-center justify-center rounded-xl ${RES_TYPE_COLORS[entry.resource_type]} shrink-0`}>
                      {RES_TYPE_ICONS[entry.resource_type]}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-white text-sm font-bold truncate">{entry.resource?.name}</p>
                      <p className="text-gray-500 text-[10px] uppercase font-semibold">{entry.resource?.unit?.symbol || '-'}</p>
                    </div>
                    <div className="text-right min-w-[100px]">
                      <p className="text-gray-400 text-xs font-medium uppercase tracking-tighter opacity-50 mb-0.5 whitespace-nowrap">Precio Unit.</p>
                      <p className="text-white text-sm font-bold tabular-nums">{formatCLP(Number(entry.resource?.base_price ?? 0))}</p>
                    </div>
                    <div className="w-24">
                      <p className="text-gray-400 text-xs font-medium uppercase tracking-tighter opacity-50 mb-0.5 whitespace-nowrap text-right pr-2">Rendimiento</p>
                      <input
                        type="number"
                        value={entry.coefficient}
                        onChange={(e) => updateCoeff(entry.resource_id, parseFloat(e.target.value) || 0)}
                        min={0}
                        step={0.001}
                        className="bg-gray-950 border border-white/10 rounded-xl px-3 py-1.5 text-white text-sm text-right outline-none focus:border-blue-500/50 w-full tabular-nums transition-all"
                      />
                    </div>
                    <div className="text-right min-w-[100px]">
                      <p className="text-gray-400 text-xs font-medium uppercase tracking-tighter opacity-50 mb-0.5 whitespace-nowrap">Subtotal</p>
                      <p className="text-emerald-400 text-sm font-bold tabular-nums">
                        {formatCLP(Number(entry.resource?.base_price ?? 0) * entry.coefficient)}
                      </p>
                    </div>
                    <button
                      type="button"
                      onClick={() => removeEntry(entry.resource_id)}
                      className="w-8 h-8 flex items-center justify-center rounded-lg text-gray-600 hover:text-rose-400 hover:bg-rose-500/10 transition-all opacity-0 group-hover:opacity-100"
                    >
                      <X size={16} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="px-8 py-6 border-t border-white/5 bg-gray-900/40 flex items-center justify-between">
          <button
            type="button"
            onClick={onCancel}
            className="px-6 py-3 rounded-xl border border-white/10 text-gray-400 text-sm font-semibold hover:bg-white/5 transition-all"
          >
            Cancelar
          </button>
          <button
            type="submit"
            disabled={isLoading || !name || entries.length === 0}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 disabled:bg-gray-800 disabled:text-gray-500 text-white px-8 py-3 rounded-xl transition-all font-bold shadow-lg shadow-blue-600/20 active:scale-95"
          >
            {isLoading ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : (
              <Check size={18} />
            )}
            <span>{initial?.id ? 'Guardar Cambios' : 'Crear Partida APU'}</span>
          </button>
        </div>
      </form>
    </div>
  );
}

// ÔöÇÔöÇÔöÇ APU Card ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function ApuCard({
  apu,
  onEdit,
  onDuplicate,
  onDelete,
}: {
  apu: ApuTemplate;
  onEdit: () => void;
  onDuplicate: () => void;
  onDelete: () => void;
}) {
  const [expanded, setExpanded] = useState(false);

  const materialCost = apu.apu_resources
    .filter((r) => r.resource_type === 'material')
    .reduce((s, r) => s + Number(r.resource?.base_price ?? 0) * Number(r.coefficient), 0);
  const laborCost = apu.apu_resources
    .filter((r) => r.resource_type === 'labor')
    .reduce((s, r) => s + Number(r.resource?.base_price ?? 0) * Number(r.coefficient), 0);
  const equipCost = apu.apu_resources
    .filter((r) => r.resource_type === 'equipment')
    .reduce((s, r) => s + Number(r.resource?.base_price ?? 0) * Number(r.coefficient), 0);

  return (
    <div className="group bg-gray-900/40 border border-white/8 rounded-2xl overflow-hidden hover:border-blue-500/30 transition-all duration-300 hover:shadow-2xl hover:shadow-blue-500/5 flex flex-col h-full">
      <div className="p-6 flex-1">
        <div className="flex items-start justify-between mb-4">
