export default function BudgetEditor() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');

  const { data: serverBudget, isLoading, error } = useQuery<ServerBudget>({
    queryKey: ['budget', id],
    queryFn: async () => {
      const response = await api.get(`/budgets/${id}`);
      return response.data;
    },
    enabled: !!id,
  });

  const { data: expensesSummary } = useQuery<{ total: number }>({
    queryKey: ['expenses-summary', serverBudget?.project_id],
    queryFn: () => api.get(`/expenses/summary/${serverBudget?.project_id}`).then((r) => r.data),
    enabled: !!serverBudget?.project_id,
  });

  const { data: workersSummary } = useQuery<{ total: number }>({
    queryKey: ['workers-summary', serverBudget?.project_id],
    queryFn: () => api.get(`/worker-assignments/summary/${serverBudget?.project_id}`).then((r) => r.data),
    enabled: !!serverBudget?.project_id,
  });

  const budgetCtx = useBudget(
    undefined, 
    expensesSummary?.total || 0,
    workersSummary?.total || 0
  );
  const { budget, financials } = budgetCtx;

  const { data: contingencies = [] } = useQuery<any[]>({
    queryKey: ['contingencies', serverBudget?.project_id],
    queryFn: () => api.get(`/contingencies/by-project/${serverBudget?.project_id}`).then((r) => r.data),
    enabled: !!serverBudget?.project_id,
  });

  const contingenciesTotal = contingencies.reduce((s, c) => s + Number(c.total_cost || 0), 0);

  const { mutate: performSave } = useMutation({
    mutationFn: async () => {
      const payload = {
        total_estimated_cost: financials.estimatedCost,
        total_estimated_price: budget.clientPrice || (financials.estimatedCost * 1.2),
        stages: budget.stages.map((s, sIdx) => ({
          // If the ID is a nanoid (usually shorter than a standard UUID), we don't send it so backend creates one
          id: s.id.length < 30 ? undefined : s.id, 
          name: s.name,
          position: sIdx,
          items: s.items.map((i, iIdx) => ({
            id: i.id.length < 30 ? undefined : i.id,
            name: i.name,
            unit: i.unit,
            quantity: i.quantity,
            unit_cost: i.unitPrice,
            unit_price: i.unitPrice * 1.2, // Default markup
            position: iIdx,
            apu_template_id: i.apuTemplateId,
            cubication_mode: i.cubicationMode,
            dim_length: i.dimLength,
            dim_width: i.dimWidth,
            dim_height: i.dimHeight,
            dim_thickness: i.dimThickness,
            quantity_executed: i.quantityExecuted,
          })),
        })),
      };
      return api.patch(`/budgets/${id}`, payload);
    },
    onMutate: () => {
      setSaveStatus('saving');
    },
    onSuccess: () => {
      setSaveStatus('saved');
      queryClient.invalidateQueries({ queryKey: ['budget', id] });
      setTimeout(() => setSaveStatus('idle'), 3000);
    },
    onError: () => {
      setSaveStatus('error');
      setTimeout(() => setSaveStatus('idle'), 5000);
      alert('Error al guardar el presupuesto. Por favor, intente de nuevo.');
    }
  });

  const handleSave = () => {
    performSave();
  };

  // Sync server data to local state once LOADED
