          name: s.name,
          progress: s.progress || 0,
          items: s.items?.map((i) => ({
            id: i.id,
            name: i.name,
            quantity: Number(i.quantity) || 0,
            unit: i.unit || 'glb',
            unitPrice: Number(i.unit_cost) || 0,
            total: (Number(i.quantity) || 0) * (Number(i.unit_cost) || 0),
            apuTemplateId: (i as any).apu_template_id,
            cubicationMode: (i as any).cubication_mode || 'manual',
            dimLength: Number((i as any).dim_length) || 0,
            dimWidth: Number((i as any).dim_width) || 0,
            dimHeight: Number((i as any).dim_height) || 0,
            dimThickness: Number((i as any).dim_thickness) || 0,
            quantityExecuted: Number((i as any).quantity_executed) || 0,
            realCost: Number((i as any).real_cost) || 0,
          })) || []
        })) || [],
        expenses: [], 
        workers: [],
      });
    }
  }, [serverBudget, budgetCtx.setBudget]);

  const [activeTab, setActiveTab] = useState<BudgetTab>('presupuesto');
  const [showTemplates, setShowTemplates] = useState(false);

  if (isLoading) {
