  const [cubicandoItem, setCubicandoItem] = useState<LineItem | null>(null);

  const toggleExpand = (id: string) => {
    const next = new Set(expandedItems);
    if (next.has(id)) next.delete(id); else next.add(id);
    setExpandedItems(next);
  };

  const handleSelectApu = (apu: ApuTemplate) => {
    if (selectingApuForItem) {
      onUpdateItem(selectingApuForItem, {
        apuTemplateId: apu.id,
        unitPrice: apu.unit_cost,
        unit: apu.base_unit as any,
      });
      setSelectingApuForItem(null);
    }
  };

  const handleSaveCubication = (data: { 
    quantity: number; 
    cubicationMode: string; 
    dimLength?: number; 
    dimWidth?: number; 
    dimHeight?: number; 
    dimThickness?: number; 
    formula: string; 
    geometryData: any; 
  }) => {
    if (cubicandoItem) {
      onUpdateItem(cubicandoItem.id, {
        quantity: data.quantity,
        cubicationMode: data.cubicationMode as any,
        dimLength: data.dimLength,
        dimWidth: data.dimWidth,
        dimHeight: data.dimHeight,
        dimThickness: data.dimThickness,
        formula: data.formula,
        geometryData: data.geometryData,
