      setCubicandoItem(null);
    }
  };

  const stageTotal = calcStageTotal(stage);

  return (
    <div className="mb-4 rounded-xl overflow-hidden border border-white/8 bg-gray-900/50 shadow-lg shadow-black/20">
      {/* Header */}
      <div className="flex items-center gap-2 px-4 py-3 bg-gray-800/60 backdrop-blur-sm">
        <button onClick={() => setCollapsed((c) => !c)} className="text-gray-400 hover:text-white transition-colors">
          {collapsed ? <ChevronRight size={16} /> : <ChevronDown size={16} />}
        </button>

        <div className="flex-1 text-sm font-bold text-white">
          <EditableCell
            value={stage.name}
            onChange={(v) => onUpdateStage({ name: v })}
