            <Plus size={12} /> Partida
          </button>
          <button onClick={onDuplicate} className="p-1.5 text-gray-500 hover:text-white rounded-lg transition-colors"><Copy size={13} /></button>
          <button onClick={onDelete} className="p-1.5 text-gray-500 hover:text-rose-400 rounded-lg transition-colors"><Trash2 size={13} /></button>
        </div>
      </div>

      {!collapsed && (
        <div className="overflow-x-auto">
          {stage.items.length > 0 && (
            <div className="grid grid-cols-[32px_1fr_90px_60px_100px_100px_100px_80px] gap-0 px-4 py-2 bg-gray-800/30 border-b border-white/5 text-[10px] font-bold text-gray-500 uppercase tracking-widest items-center">
              <span />
              <span>Partida</span>
              <span className="text-right">Cantidad</span>
              <span className="text-center">Unidad</span>
              <span className="text-right">Costo Unit.</span>
              <span className="text-right">Total Est.</span>
              <span className="text-right text-emerald-400">Ejecutado</span>
              <span className="text-center">Acciones</span>
            </div>
          )}

          {stage.items.map((item) => (
            <div key={item.id} className={`border-b border-white/5 transition-colors ${hoveredItem === item.id ? 'bg-white/2' : ''}`} onMouseEnter={() => setHoveredItem(item.id)} onMouseLeave={() => setHoveredItem(null)}>
              {/* Main Item Row */}
              <div className="grid grid-cols-[32px_1fr_90px_60px_100px_100px_100px_80px] gap-0 items-center px-4 py-1.5">
