import React, { useEffect, useRef, useState } from 'react';
import DxfParser from 'dxf-parser';
import * as fabric from 'fabric';

interface CADViewerProps {
  dxfString: string;
  onSelectGeometry: (area: number, length: number, layer: string) => void;
}

type DxfEntity = {
  type: string;
  layer: string;
  color?: number;
  vertices: { x: number; y: number }[];
  radius?: number;
  center?: { x: number; y: number };
  shape?: boolean;
};

export const CADViewer: React.FC<CADViewerProps> = ({ dxfString, onSelectGeometry }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<fabric.Canvas | null>(null);
  const [layers, setLayers] = useState<string[]>([]);
  const [selectedLayer, setSelectedLayer] = useState<string>('all');

  useEffect(() => {
    if (!containerRef.current) return;

    const canvas = new fabric.Canvas('dxf-canvas', {
      width: containerRef.current.clientWidth,
      height: containerRef.current.clientHeight,
      backgroundColor: '#111',
      selection: false
    });
    canvasRef.current = canvas;

    const handleResize = () => {
      if (containerRef.current) {
        canvas.setDimensions({
          width: containerRef.current.clientWidth,
          height: containerRef.current.clientHeight
        });
      }
    };
    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      canvas.dispose();
    };
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !dxfString) return;

    try {
      const parser = new DxfParser();
      const dxf = parser.parseSync(dxfString);
      if (!dxf) return;

      canvas.clear();
      canvas.backgroundColor = '#111';

      const foundLayers = new Set<string>();
      const objects: fabric.Object[] = [];

      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;

      function updateBounds(x: number, y: number) {
        minX = Math.min(minX, x); maxX = Math.max(maxX, x);
        minY = Math.min(minY, y); maxY = Math.max(maxY, y);
      }

      dxf.entities.forEach((entity: any) => {
        if (selectedLayer !== 'all' && entity.layer !== selectedLayer) return;
        foundLayers.add(entity.layer);

        let fabricObj: fabric.Object | null = null;

        if (entity.type === 'LINE') {
          fabricObj = new fabric.Line([entity.vertices[0].x, entity.vertices[0].y, entity.vertices[1].x, entity.vertices[1].y], {
            stroke: entity.color ? `#${entity.color.toString(16).padStart(6, '0')}` : '#888',
            strokeWidth: 1,
            selectable: true,
            hasControls: false,
            hasBorders: true
          });
          (fabricObj as any).data = entity;
          updateBounds(entity.vertices[0].x, entity.vertices[0].y);
          updateBounds(entity.vertices[1].x, entity.vertices[1].y);
        } else if (entity.type === 'LWPOLYLINE' || entity.type === 'POLYLINE') {
          const points = entity.vertices.map((v: { x: number; y: number }) => ({ x: v.x, y: v.y }));
          fabricObj = new fabric.Polyline(points, {
            stroke: entity.color ? `#${entity.color.toString(16).padStart(6, '0')}` : '#3b82f6',
            strokeWidth: 1,
            fill: entity.shape ? 'rgba(59, 130, 246, 0.1)' : 'transparent',
            selectable: true,
            hasControls: false,
            hasBorders: true
          });
          (fabricObj as any).data = entity;
          points.forEach((p: { x: number; y: number }) => updateBounds(p.x, p.y));
        } else if (entity.type === 'CIRCLE') {
          fabricObj = new fabric.Circle({
            radius: entity.radius,
            left: entity.center.x,
            top: entity.center.y,
            stroke: '#888',
            strokeWidth: 1,
            fill: 'transparent',
            selectable: true,
            hasControls: false,
            originX: 'center',
            originY: 'center'
          });
          (fabricObj as any).data = entity;
          updateBounds(entity.center.x - entity.radius, entity.center.y - entity.radius);
          updateBounds(entity.center.x + entity.radius, entity.center.y + entity.radius);
        }

        if (fabricObj) {
          objects.push(fabricObj);
        }
      });

      setLayers(['all', ...Array.from(foundLayers)]);

      if (objects.length > 0) {
        const group = new fabric.Group(objects);

        // Auto-scale and center
        const width = maxX - minX;
        const height = maxY - minY;
        const scale = Math.min(
          (canvas.width! * 0.9) / width,
          (canvas.height! * 0.9) / height
        );

        canvas.add(group);
        canvas.setViewportTransform([scale, 0, 0, -scale, canvas.width! / 2 - (minX + width / 2) * scale, canvas.height! / 2 + (minY + height / 2) * scale]);
        canvas.requestRenderAll();
      }

      canvas.on('mouse:down', (options) => {
        const target = options.target as any;
        if (target && target.data) {
          const entity = target.data as DxfEntity;
          let area = 0;
          let length = 0;

          if (entity.type === 'LWPOLYLINE' || entity.type === 'POLYLINE') {
            for (let i = 0; i < entity.vertices.length; i++) {
              const v1 = entity.vertices[i];
              const v2 = entity.vertices[(i + 1) % entity.vertices.length];
              area += (v1.x * v2.y) - (v2.x * v1.y);
              length += Math.sqrt(Math.pow(v2.x - v1.x, 2) + Math.pow(v2.y - v1.y, 2));
            }
            area = Math.abs(area) / 2;
          } else if (entity.type === 'LINE') {
            length = Math.sqrt(Math.pow(entity.vertices[1].x - entity.vertices[0].x, 2) + Math.pow(entity.vertices[1].y - entity.vertices[0].y, 2));
          } else if (entity.type === 'CIRCLE') {
            area = Math.PI * Math.pow(entity.radius || 0, 2);
            length = 2 * Math.PI * (entity.radius || 0);
          }

          onSelectGeometry(area, length, entity.layer);

          // Flash effect
          target.set('stroke', '#fbbf24');
          canvas.requestRenderAll();
          setTimeout(() => {
            if (target) {
              target.set('stroke', entity.color ? `#${entity.color.toString(16).padStart(6, '0')}` : '#3b82f6');
              canvas.requestRenderAll();
            }
          }, 500);
        }
      });


    } catch (err) {
      console.error('DXF Parse Error', err);
    }
  }, [dxfString, selectedLayer, onSelectGeometry]);

  return (
    <div className="flex flex-col gap-4 w-full h-full">
      <div className="flex items-center gap-4 px-4 bg-muted/30 py-2 rounded-xl border border-border">
        <label className="text-[10px] text-muted-foreground uppercase font-black tracking-widest">Capa (Layer):</label>
        <select 
          value={selectedLayer}
          onChange={(e) => setSelectedLayer(e.target.value)}
          className="bg-background border border-border rounded-lg px-3 py-1.5 text-xs text-foreground outline-none focus:ring-2 focus:ring-blue-500/30 transition-all font-semibold"
        >
          {layers.map(l => <option key={l} value={l}>{l}</option>)}
        </select>
        <div className="flex-1" />
        <span className="text-[10px] text-muted-foreground italic font-medium uppercase tracking-tight">Click en l├¡neas para medir</span>
      </div>

      <div ref={containerRef} className="relative flex-1 bg-neutral-900 rounded-2xl overflow-hidden border border-border min-h-[400px] shadow-inner">
        <canvas id="dxf-canvas" />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import api from '../../../lib/api';
import { Plus, Trash2, AlertTriangle } from 'lucide-react';

interface Contingency {
  id: string;
  project_id: string;
  description: string;
  quantity: number;
  unit_cost: number;
  total_cost: number;
  date: string;
}

interface Props {
  projectId: string;
}

function formatCLP(v: number) {
  return new Intl.NumberFormat('es-CL', { style: 'currency', currency: 'CLP', maximumFractionDigits: 0 }).format(v);
}

export function ContingenciesTab({ projectId }: Props) {
  const queryClient = useQueryClient();
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState({ description: '', quantity: 1, unit_cost: 0 });

  const { data: contingencies = [], isLoading } = useQuery<Contingency[]>({
    queryKey: ['contingencies', projectId],
    queryFn: () => api.get(`/contingencies/by-project/${projectId}`).then((r) => r.data),
    enabled: !!projectId,
  });

  const createMutation = useMutation({
    mutationFn: (data: any) => api.post('/contingencies', { ...data, project_id: projectId }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['contingencies', projectId] });
      setForm({ description: '', quantity: 1, unit_cost: 0 });
      setOpen(false);
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => api.delete(`/contingencies/${id}`),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['contingencies', projectId] }),
  });

  const total = contingencies.reduce((s, c) => s + Number(c.total_cost), 0);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.description || form.unit_cost <= 0) return;
    createMutation.mutate(form);
  };

  return (
    <div>
      {/* Header */}
      <div className="flex items-center justify-between mb-5">
        <div>
          <h3 className="text-white font-bold flex items-center gap-2">
            <AlertTriangle size={16} className="text-amber-400" />
            Contingencias e Imprevistos
          </h3>
          <p className="text-gray-400 text-sm mt-0.5">
            Total: <span className="text-amber-400 font-bold">{formatCLP(total)}</span>
          </p>
        </div>
        <button
          onClick={() => setOpen(true)}
          className="flex items-center gap-1.5 bg-amber-500/20 hover:bg-amber-500/30 text-amber-400 border border-amber-500/30 text-sm font-medium px-4 py-2 rounded-xl transition-colors"
        >
          <Plus size={14} /> Registrar imprevisto
        </button>
      </div>

      {/* Form modal */}
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setOpen(false)} />
          <form
            onSubmit={handleSubmit}
            className="relative bg-gray-900 border border-white/10 rounded-2xl w-full max-w-sm p-6 shadow-2xl z-10 space-y-4"
          >
            <h3 className="text-white font-bold text-lg flex items-center gap-2">
              <AlertTriangle size={16} className="text-amber-400" /> Nueva Contingencia
            </h3>

            <div>
              <label className="text-xs text-gray-400 mb-1 block">Descripci├│n</label>
              <input
                value={form.description}
                onChange={(e) => setForm({ ...form, description: e.target.value })}
                required
                placeholder="Ej: Refuerzo estructura no contemplado"
                className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm outline-none focus:border-amber-500"
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-xs text-gray-400 mb-1 block">Cantidad</label>
                <input
                  type="number"
                  value={form.quantity}
                  onChange={(e) => setForm({ ...form, quantity: parseFloat(e.target.value) || 1 })}
                  min={1}
                  step={0.1}
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm outline-none focus:border-amber-500"
                />
              </div>
              <div>
                <label className="text-xs text-gray-400 mb-1 block">Costo unitario ($)</label>
                <input
                  type="number"
                  value={form.unit_cost || ''}
                  onChange={(e) => setForm({ ...form, unit_cost: parseFloat(e.target.value) || 0 })}
                  required
                  min={1}
                  className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm outline-none focus:border-amber-500"
                />
              </div>
            </div>

            <div className="bg-amber-500/10 border border-amber-500/20 rounded-xl px-3 py-2 text-center">
              <p className="text-xs text-gray-400">Total contingencia</p>
              <p className="text-amber-400 font-black text-lg">
                {formatCLP(form.quantity * form.unit_cost)}
              </p>
            </div>

            <div className="flex gap-3">
              <button type="button" onClick={() => setOpen(false)} className="flex-1 py-2.5 rounded-xl border border-white/10 text-gray-400 text-sm hover:bg-white/5 transition-colors">
                Cancelar
              </button>
              <button
                type="submit"
                disabled={createMutation.isPending}
                className="flex-1 py-2.5 rounded-xl bg-amber-600 hover:bg-amber-700 text-white text-sm font-medium transition-colors"
              >
                Registrar
              </button>
            </div>
          </form>
        </div>
      )}

      {/* List */}
      {isLoading ? (
        <div className="flex justify-center py-16">
          <div className="w-6 h-6 border-2 border-amber-500/30 border-t-amber-500 rounded-full animate-spin" />
        </div>
      ) : contingencies.length === 0 ? (
        <div className="text-center py-16 text-gray-600">
          <p className="text-4xl mb-3">ÔÜá´©Å</p>
          <p>Sin contingencias registradas</p>
          <p className="text-sm mt-1 text-gray-700">Los imprevistos se suman al costo real sin modificar el presupuesto</p>
        </div>
      ) : (
        <div className="space-y-2">
          {contingencies.map((c) => (
            <div key={c.id} className="flex items-center gap-3 p-4 bg-amber-500/5 border border-amber-500/15 rounded-xl group hover:border-amber-500/30 transition-all">
              <AlertTriangle size={16} className="text-amber-400 shrink-0" />
              <div className="flex-1">
                <p className="text-white text-sm font-medium">{c.description}</p>
                <p className="text-gray-500 text-xs mt-0.5">
                  {Number(c.quantity)} ├ù {formatCLP(Number(c.unit_cost))} ┬À {new Date(c.date).toLocaleDateString('es-CL')}
                </p>
              </div>
              <span className="text-amber-400 font-bold tabular-nums">{formatCLP(Number(c.total_cost))}</span>
              <button
                onClick={() => { if (confirm('┬┐Eliminar esta contingencia?')) deleteMutation.mutate(c.id); }}
                className="opacity-0 group-hover:opacity-100 p-1.5 rounded-lg text-gray-500 hover:text-rose-400 hover:bg-rose-500/10 transition-all"
              >
                <Trash2 size={13} />
              </button>
            </div>
          ))}

          {/* Total */}
          <div className="flex items-center justify-between bg-amber-500/15 border border-amber-500/30 rounded-xl px-4 py-3 mt-4">
            <span className="text-amber-300 font-semibold text-sm">Total imprevistos</span>
            <span className="text-amber-400 font-black text-lg tabular-nums">{formatCLP(total)}</span>
          </div>
        </div>
      )}
    </div>
  );
}

