                  <Trash2 size={13} />
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import type { Budget, FinancialSummary, Stage, LineItem } from './types';
import { nanoid } from './utils';

// ÔöÇÔöÇÔöÇ Financial computations ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export function calcLineItem(item: Omit<LineItem, 'total'>): LineItem {
  return { ...item, total: item.quantity * item.unitPrice };
}

export function calcStageTotal(stage: Stage): number {
  return stage.items.reduce((sum, i) => sum + i.total, 0);
}

export function calcFinancials(
  budget: Budget,
  apiRealExpenses: number = 0,
  apiWorkerPayments: number = 0
): FinancialSummary {
  const estimatedCost = budget.stages.reduce(
    (s, stage) => s + calcStageTotal(stage),
    0
  );

  // Use API values if provided, fallback to legacy local arrays if API values are not provided or arrays exist
  const realExpenses = apiRealExpenses || (budget.expenses?.reduce((s, e) => s + e.amount, 0) || 0);
  const workerPayments = apiWorkerPayments || (budget.workers?.reduce((s, w) => s + (w as any).totalPaid, 0) || 0);

  const totalRealCost = realExpenses + workerPayments;
  const projectedProfit = budget.clientPrice - estimatedCost;
  const currentProfit = budget.clientPrice - totalRealCost;
  const margin =
    budget.clientPrice > 0
      ? Math.round((projectedProfit / budget.clientPrice) * 100)
      : 0;

  const executedValue = budget.stages.reduce(
    (s, stage) => s + stage.items.reduce((sum, i) => sum + ((i.quantityExecuted || 0) * i.unitPrice), 0),
    0
  );

  return {
    estimatedCost,
    realExpenses,
    workerPayments,
    totalRealCost,
    projectedProfit,
    currentProfit,
    margin,
    executedValue,
  };
}

// ÔöÇÔöÇÔöÇ Formatters ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export function formatCLP(value: number): string {
  return new Intl.NumberFormat('es-CL', {
    style: 'currency',
    currency: 'CLP',
    maximumFractionDigits: 0,
  }).format(value);
}

// ÔöÇÔöÇÔöÇ Stage / item helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export function newStage(name: string): Stage {
  return { id: nanoid(), name, progress: 0, items: [] };
}

export function newLineItem(): LineItem {
  return {
    id: nanoid(),
    name: '',
    quantity: 1,
    unit: 'm2',
    unitPrice: 0,
    costCode: '',
    total: 0,
  };
}

export interface LineItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  unitPrice: number;
  costCode?: string;
  total: number; // computed: quantity * unitPrice
  // APU & cubicacion
  apuTemplateId?: string;
  cubicationMode?: 'manual' | 'dimensions' | 'cad' | 'pdf';
  dimLength?: number;
  dimWidth?: number;
  dimHeight?: number;
  dimThickness?: number;
  formula?: string;
  geometryData?: any;
  // Ejecuci├│n real
  quantityExecuted?: number;
  realCost?: number;
}

export interface Stage {
  id: string;
  name: string;
  progress: number; // 0ÔÇô100
  items: LineItem[];
}

export interface Expense {
  id: string;
  category: 'material' | 'transport' | 'tools' | 'contingency';
  expense_type?: string;
  description: string;
  amount: number;
  date: string;
  document_url?: string;
}

export interface Worker {
  id: string;
  name: string;
  specialty: string;
  dailyRate: number;
  daysWorked: number;
  totalPaid: number;
  phone?: string;
  performance?: number; // 1-5
  notes?: string;
}

export interface Budget {
  id: string;
  projectName: string;
  clientName: string;
  status: 'draft' | 'editing' | 'sent' | 'approved';
  clientPrice: number;
  stages: Stage[];
  expenses: Expense[];
  workers: Worker[];
}

// Derived financials (computed from Budget)
export interface FinancialSummary {
  estimatedCost: number;
  realExpenses: number;
  workerPayments: number;
  totalRealCost: number;
  projectedProfit: number;
  currentProfit: number;
  margin: number; // percentage
  executedValue: number; // Sum of (quantityExecuted * unitPrice)
}

