import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import api from '../../lib/api';
import {
  Package, HardHat, Wrench, Plus, Pencil, Trash2,
  Search, X, Check, History
} from 'lucide-react';

type ResourceType = 'material' | 'labor' | 'equipment';

interface Resource {
  id: string;
  name: string;
  type: ResourceType;
  unit_id: string;
  unit?: { symbol: string; name: string };
  base_price: number;
  description?: string;
  created_at: string;
}

interface Unit {
  id: string;
  name: string;
  symbol: string;
  category: string;
}

interface PriceHistory {
  id: string;
  price: number;
  date: string;
}

const TYPE_CONFIG: Record<ResourceType, { label: string; icon: React.ReactNode; color: string; bg: string }> = {
  material: { label: 'Material', icon: <Package size={14} />, color: 'text-blue-400', bg: 'bg-blue-500/15 border-blue-500/30' },
  labor: { label: 'Mano de obra', icon: <HardHat size={14} />, color: 'text-violet-400', bg: 'bg-violet-500/15 border-violet-500/30' },
  equipment: { label: 'Equipos', icon: <Wrench size={14} />, color: 'text-amber-400', bg: 'bg-amber-500/15 border-amber-500/30' },
};

// UNITS is now fetched from API

function formatCLP(v: number) {
  return new Intl.NumberFormat('es-CL', { style: 'currency', currency: 'CLP', maximumFractionDigits: 0 }).format(v);
}

interface ResourceFormProps {
  initial?: Partial<Resource>;
  onSave: (data: Omit<Resource, 'id' | 'created_at'>) => void;
  onCancel: () => void;
  isLoading?: boolean;
  units: Unit[];
}

function ResourceForm({ initial, onSave, onCancel, isLoading, units }: ResourceFormProps) {
  const [form, setForm] = useState({
    name: initial?.name ?? '',
    type: initial?.type ?? 'material' as ResourceType,
    unit_id: initial?.unit_id ?? '',
    base_price: initial?.base_price ?? 0,
    description: initial?.description ?? '',
  });

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/70 backdrop-blur-sm" onClick={onCancel} />
      <form
        onSubmit={(e) => { e.preventDefault(); onSave(form as any); }}
        className="relative bg-gray-900 border border-white/15 rounded-2xl w-full max-w-md p-6 shadow-2xl z-10 space-y-4"
      >
        <h3 className="text-white font-bold text-lg">{initial?.id ? 'Editar Recurso' : 'Nuevo Recurso'}</h3>

        <div>
          <label className="text-xs text-gray-400 mb-1 block">Nombre</label>
          <input
            value={form.name}
            onChange={(e) => setForm({ ...form, name: e.target.value })}
            required
            placeholder="Ej: Hormig├│n H25"
            className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500 transition-colors"
          />
        </div>

        <div>
          <label className="text-xs text-gray-400 mb-1 block">Descripci├│n (opcional)</label>
          <textarea
            value={form.description}
            onChange={(e) => setForm({ ...form, description: e.target.value })}
            placeholder="Detalles adicionales..."
            rows={2}
            className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2 text-white text-sm outline-none focus:border-blue-500 transition-colors resize-none"
          />
        </div>

        <div className="grid grid-cols-3 gap-2">
          {(Object.keys(TYPE_CONFIG) as ResourceType[]).map((t) => (
            <button
              key={t}
              type="button"
              onClick={() => setForm({ ...form, type: t })}
              className={`flex flex-col items-center gap-1 py-2.5 rounded-xl border text-xs font-medium transition-all ${
                form.type === t
                  ? `${TYPE_CONFIG[t].bg} ${TYPE_CONFIG[t].color} border-opacity-80`
                  : 'border-white/10 text-gray-500 hover:border-white/20 hover:text-gray-300'
              }`}
            >
              {TYPE_CONFIG[t].icon}
              {TYPE_CONFIG[t].label}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="text-xs text-gray-400 mb-1 block">Unidad</label>
            <select
              value={form.unit_id}
              onChange={(e) => setForm({ ...form, unit_id: e.target.value })}
              required
              className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm outline-none focus:border-blue-500"
            >
              <option value="" disabled>Seleccionar...</option>
              {units.map((u) => <option key={u.id} value={u.id}>{u.symbol} - {u.name}</option>)}
            </select>
          </div>
          <div>
            <label className="text-xs text-gray-400 mb-1 block">Precio base ($)</label>
            <input
              type="number"
              value={form.base_price || ''}
              onChange={(e) => setForm({ ...form, base_price: parseFloat(e.target.value) || 0 })}
              min={0}
              required
              className="w-full bg-gray-800 border border-white/10 rounded-xl px-3 py-2.5 text-white text-sm outline-none focus:border-blue-500"
            />
          </div>
        </div>

        <div className="flex gap-3 pt-2">
          <button
            type="button"
            onClick={onCancel}
            className="flex-1 py-2.5 rounded-xl border border-white/10 text-gray-400 text-sm hover:bg-white/5 transition-colors"
          >
            Cancelar
          </button>
          <button
            type="submit"
            disabled={isLoading}
            className="flex-1 py-2.5 rounded-xl bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium transition-colors flex items-center justify-center gap-2"
          >
            {isLoading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Check size={14} />}
            {initial?.id ? 'Guardar cambios' : 'Crear recurso'}
          </button>
        </div>
      </form>
    </div>
  );
}

